using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Preserve EF Core 8 id format ("Product|123") for existing 500K documents
        optionsBuilder.UseCosmos(o =>
            o.ConfigureWarnings(w => { }));
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change: HasIndex now throws for Cosmos provider — removed.

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Existing documents and raw SQL queries use "Discriminator", so keep the old name.
            entity.HasDiscriminant("Discriminator");

            // EF9 breaking change: id values changed from "EntityType|Key" to just "Key".
            // Existing 500K documents use "Product|123" format, so preserve it.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

